import{_ as t,o as r,c as a,a3 as n}from"./chunks/framework.BjwLbrw5.js";const f=JSON.parse('{"title":"Адаптивные шрифты","description":"","frontmatter":{"title":"Адаптивные шрифты","date":"2020-09-11 17:00"},"headers":[],"relativePath":"posts/2020-09-11-adaptive-fonts.md","filePath":"posts/2020-09-11-adaptive-fonts.md"}'),p={name:"posts/2020-09-11-adaptive-fonts.md"};function s(o,e,i,m,l,c){return r(),a("div",null,[...e[0]||(e[0]=[n(`<p>Первые попытки резиновой, то есть, адаптирующейся к ширине экрана, верстки были аж в 2004-ом году, судя по <a href="http://www.themaninblue.com/writing/perspective/2004/09/21/" target="_blank" rel="noreferrer">чудом сохранившейся статье в блоге Man in Blue</a></p><p>Когда адаптивность стала входить в обиход (точкой отсчета принято считать <a href="https://alistapart.com/article/responsive-web-design/" target="_blank" rel="noreferrer">эту статью Итана Маркотта</a>, то есть 10 лет назад, мы использовали <em>%</em> и <em>em</em> в качестве единиц измерения для шрифтов и отступов. Чтобы увеличить или уменьшить шрифт, мы использовали <em>media queries</em>, которые позволяли задать <em>font-size</em> для body, от которого зависят все размеры, указанные в em-ах.</p><p>Верстальщику всё время нужно было подбирать определенную величину, при которой блоки не наезжали друг на друга, текст не выпячивал за пределы блока, учитывать читаемость и компоновку элементов для четырёх размеров экранов как минимум.</p><p>Все современные браузеры поддерживают <em>vw</em> и <em>vh</em> в качестве величин, относительных высоте и ширине viewport-а (окна браузера). Если вы потянете за угол окна браузера прямо сейчас, вы сможете заметить, что заголовок страницы будет плавно уменьшаться, это потому что его размер шрифта указан в <em>vw</em>. Раньше это можно было сделать, указав размер в процентах, но эти проценты считались от ширины блока.</p><p>Чтобы текст не ужимался до нечитабельного состояния, можно указать минимальный размер через calc():</p><pre><code>h1 {
    font-size: calc(1.3rem + 3.6vw);
}
</code></pre><p>Несмотря на то, что эта технология появилась 8 лет назад, вместе с CSS3 (<a href="https://generatedcontent.org/post/21279324555/viewportunits" target="_blank" rel="noreferrer">одна из первых статей про vueport units</a>), огромное число разработчиков до сих пор оперируют пикселями и, в лучшем случае, <em>em</em>. Оставим это на их совести и совести UX-специалистов, которые делают статичные макеты.</p><p>Почаще заходите сюда, и на <a href="https://caniuse.com/viewport-units" target="_blank" rel="noreferrer">Can I Use</a>, и здесь и там очень много полезной и актуальной информации.</p><p>Да, читайте, пожалуйста, <a href="https://www.w3.org/TR/css3-values/#viewport-relative-lengths" target="_blank" rel="noreferrer">спецификацию</a>!</p>`,9)])])}const d=t(p,[["render",s]]);export{f as __pageData,d as default};
